const d = $('Get EOD Brief').first().json;
const date = d.date || new Date().toISOString().split('T')[0];
const summary = d.today_summary || {};
const missions = d.missions || {};
const pending = d.still_pending || [];
const resolved = d.resolved_today || [];
const plan = d.overnight_plan || [];

const pendingRows = pending.map(i => `<li><strong>${i.exec_id}</strong> — ${i.title}${i.deadline ? ` <span style="color:#eab308;">(due ${i.deadline})</span>` : ''}</li>`).join('');
const resolvedRows = resolved.map(i => `<li>${i.exec_id} → <strong>${i.resolution}</strong></li>`).join('');
const planItems = plan.map(p => `<li>${p}</li>`).join('');

const subject = `HCI AI EOD — ${date} · ${summary.decisions_pending||0} pending · ${summary.mining_runs||0} mining runs`;

const html = `<html><body style="font-family:sans-serif;background:#111827;color:#f9fafb;padding:20px;max-width:600px;">
<h2 style="color:#3b82f6;">HCI AI — End of Day · ${date}</h2>
<div style="background:#1f2937;border-radius:8px;padding:16px;margin-bottom:12px;">
  <strong>Today's Activity</strong><br/>
  Mining runs: ${summary.mining_runs||0} · Decisions resolved: ${summary.decisions_resolved||0} · ROI: ${d.roi_hours_this_week||0}h total
</div>
${resolved.length ? `<div style="background:#14532d;border-radius:8px;padding:16px;margin-bottom:12px;"><strong>Resolved Today</strong><ul>${resolvedRows}</ul></div>` : ''}
${pending.length ? `<div style="background:#7f1d1d;border-radius:8px;padding:16px;margin-bottom:12px;"><strong>Still Pending (${pending.length})</strong><ul>${pendingRows}</ul></div>` : '<div style="background:#14532d;border-radius:8px;padding:16px;margin-bottom:12px;">No pending decisions</div>'}
<div style="background:#1f2937;border-radius:8px;padding:16px;margin-bottom:12px;">
  <strong>Overnight Plan</strong><ul>${planItems}</ul>
</div>
<div style="background:#1f2937;border-radius:8px;padding:16px;margin-bottom:12px;">
  <strong>Projects</strong>${(d.projects||[]).map(p=>`<div>${p}</div>`).join('')}
</div>
<p><a href="http://host.docker.internal:8000/executive" style="background:#3b82f6;color:white;padding:10px 20px;border-radius:6px;text-decoration:none;">Open Dashboard</a></p>
</body></html>`;
return [{json:{subject,html,to:'buck@ahmaspen.com'}}];

